form:Form.form:Scripts:
		function ClearEmpresa()
{
	Ctrl("oi_empresa").SetCValue("");                     
	ClearPuesto();
}

function ClearPuesto()
{                     
	Ctrl("oi_puesto").SetCValue("");
	ClearPosicion();
}

function ClearPosicion()
{                     
	Ctrl("oi_posicion").SetCValue("");
}



function EJECUTAR_CLICK()
{                             
	if (Ctrl("oi_empresa").GetXValue()=="") { alert("La Empresa es Requerida."); return false; }      
	if (Ctrl("oi_aniomes").GetXValue()=="") { alert("Mes/Año es Requerido."); return false; }

	if (!Ctrl("main").Validate()) return false;

	var mdx = " with ";


mdx += "   member [Measures].[Puntaje] as '[Measures].[Result_eval]'" ;  
mdx += "   member [Measures].[Maximo] as 'Max({[Estructura].CurrentMember, [Estructura].Children}, [Measures].[Puntaje])'" ; 
mdx += "   member [Measures].[Minimo] as 'Min({[Estructura].CurrentMember, [Estructura].Children}, [Measures].[Puntaje])'" ;
mdx += " select NON EMPTY {[Measures].[Cantidad], [Measures].[Puntaje], [Measures].[Minimo], [Measures].[Maximo]} ON COLUMNS," ; 
mdx += " NON EMPTY Hierarchize(Union({([Evento].[Todos los Eventos], [Estructura].[Todo las Estructuras])}, Crossjoin([Evento].[Todos los Eventos].Children, {[Estructura].[Todo las Estructuras]}))) ON ROWS " ; 



  /*
	if(Ctrl("oi_empresa").GetText(1)!="")
		{mdx += " NON EMPTY Hierarchize(Union([Estructura].[Todo las Estructuras].[" ;
		mdx +=  Ctrl("oi_empresa").GetText(1) + "].Children, [Estructura].[Todo las Estructuras].[" ;
		mdx +=  Ctrl("oi_empresa").GetText(1) + "].Children  )) ON ROWS" ;
		 }


	else
	{
		mdx += ", ([Grupos Sueldos].[Todos los Grupos Sueldos] , [Measures].[Horas]), DESC) ON ROWS ";    

		}
		  */




	mdx += " from [EVALUACION]  ";

	var where = "";
	if(Ctrl("oi_aniomes").GetCValue()!="")
		where += "[Tiempo].[" + Ctrl("oi_aniomes").GetCValue().split("/")[1] + "].[" + Ctrl("oi_aniomes").GetCValue() + "],";

	if(Ctrl("oi_empresa").GetText(1)!="")
		where += "[Empresas].[" + Ctrl("oi_empresa").GetText(1) + "],";


	if(where!="")
	{                   
		mdx += "where {(" + where.substr(0, where.length-1) + ")}";
	}




    //alert(mdx);

	Ctrl("mdx").SetXValue(mdx);

	Ctrl("main").DoEvent("EJECUTAR_CLICK");
	return true;
}
